-- Session 3.2.2 — auto-org-create + contractor profile upsert RPCs.
--
--   create_org_with_contractor_profile(name, slug, profile_data jsonb)
--     Solo-user "Визитка" flow: creates an organization (the
--     on_organization_owner_membership trigger adds the owner org_members row),
--     plus a draft contractor_profiles row, in one transaction.
--   upsert_contractor_profile_for_org(org_id, profile_data jsonb)
--     Existing-org "Визитка" flow: INSERT, or UPDATE the single profile per org
--     (one-profile-per-org is enforced by idx_contractor_profiles_one_per_org).
--   submit_contractor_profile_for_moderation(org_id)
--     Flips a draft profile to pending_moderation.
--
-- All three are security definer. The org-create case is chicken-and-egg: the
-- contractor_profiles INSERT policy needs can_manage_org, which is only true
-- once the org + owner membership exist. The functions still authorize
-- explicitly (auth.uid() present; can_manage_org for the existing-org paths).
--
-- These management RPCs are curated (parsed for validation) but, like the
-- existing org RPCs, are not projected onto a slice contract.
--
-- Also adds contractor_profiles.inn (optional taxpayer id). One profile per org,
-- so it is effectively the org's ИНН; a later session uses it to mark verified
-- orgs. Threaded through both RPCs below.

-- contractor_profiles.inn: optional taxpayer id (ИНН), used later to mark
-- verified organizations. (No `comment on column` — the curated mirror parser
-- does not model it.)
alter table public.contractor_profiles
  add column if not exists inn text;

create or replace function public.create_org_with_contractor_profile(
  p_org_name text,
  p_org_slug text,
  p_profile_data jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user_id uuid := auth.uid();
  v_org_id uuid;
  v_profile_id uuid;
  v_specializations text[];
begin
  if v_user_id is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if p_org_name is null or length(trim(p_org_name)) = 0 then
    raise exception 'Org name required' using errcode = '22023';
  end if;
  if p_org_slug is null or p_org_slug !~ '^[a-z0-9][a-z0-9-]{0,38}[a-z0-9]$' then
    raise exception 'Invalid slug format: %', coalesce(p_org_slug, '(null)')
      using errcode = '22023';
  end if;
  -- Surface a clear collision error so the UI can prompt the user to edit the
  -- slug rather than auto-appending a surprise suffix.
  if exists (select 1 from public.organizations where slug = p_org_slug) then
    raise exception 'Slug already exists: %', p_org_slug using errcode = '23505';
  end if;

  v_specializations := coalesce(
    (
      select array_agg(elem)
      from jsonb_array_elements_text(
        coalesce(p_profile_data -> 'specializations', '[]'::jsonb)
      ) as elem
    ),
    '{}'::text[]
  );

  insert into public.organizations (name, slug, owner_profile_id)
  values (trim(p_org_name), p_org_slug, v_user_id)
  returning id into v_org_id;

  insert into public.contractor_profiles (
    org_id, display_name, contacts, region, specializations,
    experience_years, avatar_url, description, inn, status, created_by
  ) values (
    v_org_id,
    coalesce(nullif(trim(p_profile_data ->> 'display_name'), ''), trim(p_org_name)),
    coalesce(p_profile_data -> 'contacts', '{}'::jsonb),
    nullif(trim(p_profile_data ->> 'region'), ''),
    v_specializations,
    nullif(p_profile_data ->> 'experience_years', '')::integer,
    nullif(trim(p_profile_data ->> 'avatar_url'), ''),
    nullif(trim(p_profile_data ->> 'description'), ''),
    nullif(trim(p_profile_data ->> 'inn'), ''),
    'draft',
    v_user_id
  )
  returning id into v_profile_id;

  return jsonb_build_object('org_id', v_org_id, 'profile_id', v_profile_id);
end;
$$;

create or replace function public.upsert_contractor_profile_for_org(
  p_org_id uuid,
  p_profile_data jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user_id uuid := auth.uid();
  v_profile_id uuid;
  v_specializations text[];
  v_requested_status text;
begin
  if v_user_id is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if not public.can_manage_org(p_org_id) then
    raise exception 'Not authorized to manage organization %', p_org_id
      using errcode = '42501';
  end if;

  v_specializations := coalesce(
    (
      select array_agg(elem)
      from jsonb_array_elements_text(
        coalesce(p_profile_data -> 'specializations', '[]'::jsonb)
      ) as elem
    ),
    '{}'::text[]
  );

  -- Clients may only request draft / pending_moderation. Publishing and
  -- archiving stay an admin-side concern; ignore anything else.
  v_requested_status := p_profile_data ->> 'status';
  if v_requested_status is null
     or v_requested_status not in ('draft', 'pending_moderation') then
    v_requested_status := null;
  end if;

  insert into public.contractor_profiles (
    org_id, display_name, contacts, region, specializations,
    experience_years, avatar_url, description, inn, status, created_by
  ) values (
    p_org_id,
    coalesce(nullif(trim(p_profile_data ->> 'display_name'), ''), 'Контакт'),
    coalesce(p_profile_data -> 'contacts', '{}'::jsonb),
    nullif(trim(p_profile_data ->> 'region'), ''),
    v_specializations,
    nullif(p_profile_data ->> 'experience_years', '')::integer,
    nullif(trim(p_profile_data ->> 'avatar_url'), ''),
    nullif(trim(p_profile_data ->> 'description'), ''),
    nullif(trim(p_profile_data ->> 'inn'), ''),
    coalesce(v_requested_status, 'draft'),
    v_user_id
  )
  on conflict (org_id) do update set
    display_name = coalesce(
      nullif(trim(p_profile_data ->> 'display_name'), ''),
      public.contractor_profiles.display_name
    ),
    contacts = coalesce(p_profile_data -> 'contacts', public.contractor_profiles.contacts),
    region = nullif(trim(p_profile_data ->> 'region'), ''),
    specializations = v_specializations,
    experience_years = nullif(p_profile_data ->> 'experience_years', '')::integer,
    avatar_url = nullif(trim(p_profile_data ->> 'avatar_url'), ''),
    description = nullif(trim(p_profile_data ->> 'description'), ''),
    inn = nullif(trim(p_profile_data ->> 'inn'), ''),
    status = coalesce(v_requested_status, public.contractor_profiles.status),
    updated_at = now()
  returning id into v_profile_id;

  return jsonb_build_object('org_id', p_org_id, 'profile_id', v_profile_id);
end;
$$;

create or replace function public.submit_contractor_profile_for_moderation(
  p_org_id uuid
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user_id uuid := auth.uid();
  v_profile_id uuid;
begin
  if v_user_id is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if not public.can_manage_org(p_org_id) then
    raise exception 'Not authorized to manage organization %', p_org_id
      using errcode = '42501';
  end if;

  update public.contractor_profiles
  set status = 'pending_moderation', updated_at = now()
  where org_id = p_org_id
    and status = 'draft'
  returning id into v_profile_id;

  if v_profile_id is null then
    raise exception 'No draft contractor profile to submit for org %', p_org_id
      using errcode = 'P0002';
  end if;

  return jsonb_build_object(
    'org_id', p_org_id,
    'profile_id', v_profile_id,
    'status', 'pending_moderation'
  );
end;
$$;

